type PatternRoot = Document | Element;
type Disposer = () => void;
interface Pattern {
    name: string;
    init(root?: PatternRoot): Disposer | void;
}
interface CoreHelpers {
    ready: (fn: () => void) => void;
    byAttr: (name: string, root?: PatternRoot) => NodeListOf<HTMLElement>;
}
interface Ui8KitNamespace extends CoreHelpers {
    core: CoreHelpers;
    register: (pattern: Pattern) => void;
    init: (root?: PatternRoot) => void;
    initPattern: (name: string, root?: PatternRoot) => void;
    [key: string]: unknown;
}

export type { CoreHelpers as C, Disposer as D, Pattern as P, Ui8KitNamespace as U, PatternRoot as a };
